# Define a tool that Claude can use
weather_tool = {
    "name": "get_weather",
    "description": "Get the current weather for a given city. Use this when the user asks about weather conditions, temperature, or forecasts for a specific location.",
    "input_schema": {
        "type": "object",
        "properties": {
            "city": {
                "type": "string",
                "description": "The city name, e.g. 'San Francisco' or 'Tokyo'"
            },
            "unit": {
                "type": "string",
                "enum": ["celsius", "fahrenheit"],
                "description": "Temperature unit. Default is celsius."
            }
        },
        "required": ["city"]
    }
}

# A second tool: calculator
calculator_tool = {
    "name": "calculate",
    "description": "Evaluate a mathematical expression. Use for arithmetic, conversions, or computations.",
    "input_schema": {
        "type": "object",
        "properties": {
            "expression": {
                "type": "string",
                "description": "Math expression to evaluate, e.g. '(25 * 1.08) + 15'"
            }
        },
        "required": ["expression"]
    }
}

def calculate(expression: str) -> dict:
    try:
        result = eval(expression, {"__builtins__": {}}, {})
        return {"result": result, "expression": expression}
    except Exception as e:
        return {"error": str(e)}

# Reusable agent loop
def run_agent(user_message: str, tools: list[dict], tool_funcs: dict) -> str:
    client = anthropic.Anthropic()
    messages = [{"role": "user", "content": user_message}]
    while True:
        response = client.messages.create(
            model="claude-sonnet-4-20250514", max_tokens=4096,
            tools=tools, messages=messages
        )
        if response.stop_reason == "end_turn":
            return "\n".join(b.text for b in response.content if b.type == "text")
        messages.append({"role": "assistant", "content": response.content})
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                func = tool_funcs.get(block.name)
                if func:
                    r = func(**block.input)
                    tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": json.dumps(r)})
                else:
                    tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": json.dumps({"error": f"Unknown tool: {block.name}"}), "is_error": True})
        messages.append({"role": "user", "content": tool_results})

# Claude picks the right tool(s) based on the question
print(run_agent(
    "What's the weather in Tokyo? Also, what's a 20% tip on $67.50?",
    tools=[weather_tool, calculator_tool],
    tool_funcs={"get_weather": get_weather, "calculate": calculate}
))
